// ============================================================================
// CIL v6.1 — INPUT VALIDATOR
// ============================================================================
const input = $input.item.json;
const domain = (input.domain || "GENERAL").toUpperCase().trim();
const query = input.query || input.prompt || input.message || "";
if (!query.trim()) {
  return { json: { error: true, error_message: "INPUT VALIDATOR: Missing required field 'query'.", input_received: Object.keys(input), _timestamp: new Date().toISOString() } };
}
const context = input.context || input.additional_context || "";
let domaindata = input.domaindata || input.hunterdata || input.data || {};
const runid = input.runid || `CIL-${domain}-${Date.now()}-${Math.random().toString(36).substr(2,6)}`;
if (domain === "MARKET") {
  if (domaindata.ticker) domaindata.ticker = domaindata.ticker.toUpperCase().trim();
  for (const f of ['price','volume','rsi','short_interest']) {
    if (domaindata[f] !== undefined && typeof domaindata[f] === 'string') {
      const n = parseFloat(domaindata[f]); if (!isNaN(n)) domaindata[f] = n;
    }
  }
}
return { json: { domain, query: query.trim(), context, domaindata, runid, timestamp: input.timestamp || new Date().toISOString(), _input_validator: { version: "6.1", backward_compat: input.hunterdata ? "hunterdata→domaindata" : "none", _timestamp: new Date().toISOString() } } };

// CIL v6.1 — AGENT PAYLOAD BUILDER
// Preserves 5-item output (one per agent) + uses PROMPT BUILDER systemprompts
// Models: gpt-5.4 / grok-4.1 / gemini-3.1-pro / deepseek-v3.2 / sonar-pro
const input = $input.first().json;
const agents = {
  URIEL: {
    model: 'gpt-5.4',
    format: 'openai',
    role: 'Strategic Macro Analyst',
    bias: 'Bull case builder — find the strongest path to yes'
  },
  COLOSSUS: {
    model: 'grok-4',
    format: 'xai',
    role: 'Contrarian Sentiment Analyst',
    bias: 'Contrarian by default — challenge every assumption'
  },
 HANIEL: {
  model: 'gemini-2.5-flash',
  format: 'google',
    role: 'Fundamental Research Analyst',
    bias: 'Evidence-only — no speculation, cite data sources'
  },
  RAZIEL: {
    model: 'deepseek-chat',
    format: 'deepseek',
    role: 'Adversarial Stress Tester',
    bias: 'Bear case builder — find every way this trade fails'
  },
  SARIEL: {
    model: 'sonar-pro',
    format: 'perplexity',
    role: 'Live Intelligence Analyst',
    bias: 'Recency-weighted — prioritize latest data, flag stale inputs'
  }
};
const payloads = [];
for (const [name, config] of Object.entries(agents)) {
  payloads.push({
    json: {
      // Pass ALL upstream fields through (routing, domaindata, runid, etc.)
      ...input,
      // Agent identity
      agent: name,
      model: config.model,
      format: config.format,
      // Each item carries its own named systemprompt so $json.systemprompt_URIEL etc. resolve
      [`systemprompt_${name}`]: input[`systemprompt_${name}`]
  || `You are ${name}, ${config.role}. Bias: ${config.bias}. Respond in valid JSON only.`,
systemprompt: input[`systemprompt_${name}`]
  || `You are ${name}, ${config.role}. Bias: ${config.bias}. Respond in valid JSON only.`,
      // userprompt passes through from PROMPT BUILDER
      userprompt: input.userprompt || `Analyze ${input.domaindata?.ticker || 'the provided thesis'}.`,
      _payload_builder: {
        version: '6.1',
        agent: name,
        model: config.model,
        prompt_source: input[`systemprompt_${name}`] ? 'PROMPT_BUILDER' : 'FALLBACK',
        _timestamp: new Date().toISOString()
      }
    }
  });
}
return payloads;

