// ============================================================================
// CIL v6.1 — COLLECTIVE ASSEMBLER
// ============================================================================

const items = $input.all();
const agents = ["URIEL","COLOSSUS","HANIEL","RAZIEL","SARIEL"];
const warnings = [];

// Find the PROMPT BUILDER item (has systemprompt_URIEL field)
let baseItem = null;
for (const item of items) {
  if (item.json.systemprompt_URIEL) {
    baseItem = item.json;
    break;
  }
}

if (!baseItem) {
  warnings.push("PROMPT BUILDER item not found in merged inputs");
  baseItem = items[0]?.json || {};
}

// Build agent_outputs object from merged items
const agentOutputs = {};
for (const item of items) {
  if (item.json.agent && item.json.data) {
    const agentName = item.json.agent;
    if (agents.includes(agentName)) {
      agentOutputs[agentName] = item.json.data;
    }
  }
}

// Validate prompts
for (const a of agents) {
  if (!baseItem[`systemprompt_${a}`] || baseItem[`systemprompt_${a}`].startsWith("ERROR:")) {
    warnings.push(`Missing prompt: ${a}`);
  }
}
if (!baseItem.userprompt || !baseItem.userprompt.trim()) {
  warnings.push("userprompt is empty");
}

const domaindata = baseItem.domaindata || {};
const sz = JSON.stringify(domaindata).length;
if (sz > 50000) {
  warnings.push(`domaindata is ${Math.round(sz/1024)}KB — may hit token limits`);
}

return [{ 
  json: { 
    ...baseItem, 
    domaindata, 
    agent_outputs: agentOutputs,
    _assembler: { 
      version: "6.1", 
      agents_configured: agents.length, 
      agents_received: Object.keys(agentOutputs).length,
      warnings, 
      domain: baseItem.domain, 
      runid: baseItem.runid, 
      _timestamp: new Date().toISOString() 
    } 
  } 
}];

// ============================================================================
// CIL v6.1 — CASCADE VALIDATOR
// ============================================================================

const input = $input.first().json;
const gc = input.gate_config || {};
const gates = gc.gates || [];
const agentOutputs = input.agent_outputs || {};
const domaindata = input.domaindata || {};
const targetScore = gc.target_score || 90;
const failThreshold = gc.fail_threshold || 40;

const gateResults = [];
let weightedSum = 0, totalWeight = 0, hardFails = 0;
const warnings = [];

for (const gate of gates) {
  let result;
  try {
    const fn = new Function('agentOutputs', 'domaindata', 'threshold', gate.evaluator);
    result = fn(agentOutputs, domaindata, gate.threshold);
  } catch(e) {
    result = { passed: false, score: 0, detail: `EVAL ERROR: ${e.message}` };
    warnings.push(`Gate ${gate.id} threw: ${e.message}`);
  }
  const gr = { id: gate.id, name: gate.name, weight: gate.weight, threshold: gate.threshold, score: result.score||0, passed: result.passed||false, detail: result.detail||"" };
  gateResults.push(gr);
  weightedSum += gr.score * gate.weight;
  totalWeight += gate.weight;
  if (gr.score < failThreshold) { hardFails++; warnings.push(`HARD FAIL: Gate ${gate.id} ${gate.name} @ ${gr.score}%`); }
}

const overallScore = totalWeight > 0 ? Math.round(weightedSum / totalWeight) : 0;
const passed = overallScore >= targetScore && hardFails === 0;
const confidenceLevel = overallScore >= 90 ? "HIGH" : overallScore >= 70 ? "MODERATE" : overallScore >= 50 ? "LOW" : "INSUFFICIENT";

const agents = Object.values(agentOutputs);
const totalFields = agents.reduce((s,a) => s+Object.keys(a).filter(k=>!k.startsWith('_')).length, 0);
const filledFields = agents.reduce((s,a) => s+Object.entries(a).filter(([k,v]) => !k.startsWith('_')&&v!=null&&v!==''&&v!=='INSUFFICIENT_DATA'&&!(Array.isArray(v)&&!v.length)).length, 0);

return [{ json: { ...input, cascade_result: { overall_score: overallScore, passed, confidence_level: confidenceLevel, target_score: targetScore, hard_fails: hardFails, gates_passed: gateResults.filter(g=>g.passed).length, gates_total: gateResults.length, gate_results: gateResults, data_completeness: totalFields > 0 ? Math.round((filledFields/totalFields)*100) : 0, scoring_method: "WEIGHTED_AVERAGE", warnings, domain: input.domain, runid: input.runid, _timestamp: new Date().toISOString() } } }];

