const dateStr = new Date().toISOString().split('T')[0].replace(/-/g,'');
const githubPath = `AIORA/CIL/runs/${domain}/${dateStr}_${runid}.json`;

return [{ json: {
  telegram_message: formatted.telegram_message || `🔱 CIL v6.1 | ${domain}\n❌ No output template\nRun: ${runid}`,
  github_path: githubPath,
  github_content: JSON.stringify(formatted.github_payload || { runid, domain, error: "no payload" }, null, 2),
  github_commit_message: `CIL v6.1 | ${domain} | ${runid} | ${cascadeResult.overall_score||0}%`,
  db_record: formatted.db_record || { runid, domain, error: "no record" },
  test_fields: { runid, domain, overall_score: cascadeResult.overall_score||0, cascade_passed: cascadeResult.passed||false, gates_passed: cascadeResult.gates_passed||0, gates_total: cascadeResult.gates_total||0, agent_count: Object.keys(input.agent_outputs||{}).length, synthesis_present: !!(input.synthesis||input.pass2_output), summary: formatted.summary||"" },
  summary: formatted.summary || "",
  runid, domain, cascade_result: cascadeResult,
  _output_formatter: { version: "6.1", github_path: githubPath, _timestamp: new Date().toISOString() }
}}];

// PASS1 ROUTER PARSER v1.2
const items = $input.all();
const originalInput = $('PROMPT BUILDER').first().json;

const results = [];

for (const item of items) {
  const raw = item.json;
  let routing = null;

  if (raw.error || !raw.content) {
    routing = {
      routerversion: 'PASS1_FALLBACK',
      requestclassification: originalInput.requesttype,
      complexity: 'full_cascade',
      uriel_directive: 'Provide full strategic and macro analysis.',
      colossus_directive: 'Provide full technical analysis and data verification.',
      haniel_directive: 'Provide full catalyst and data freshness analysis.',
      raziel_directive: 'Provide full counter-thesis with at least 5 failure modes.',
      sariel_directive: 'Search for the latest news and real-time data.',
      priorityagents: [],
      depriorityagents: [],
      portfoliocontext: null,
      routingrationale: 'PASS1 FAILED — using generic routing'
    };
  } else {
    try {
      const content = raw.content[0].text;
      let cleaned = content
        .replace(/^```json\s*/i, '')
        .replace(/^```\w*\s*/i, '')
        .replace(/```\s*$/i, '')
        .trim();
      const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
      routing = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
    } catch (e) {
      routing = null;
    }

    if (!routing) {
      routing = {
        routerversion: 'PASS1_PARSE_FAIL',
        requestclassification: originalInput.requesttype,
        complexity: 'full_cascade',
        uriel_directive: 'Provide full strategic and macro analysis.',
        colossus_directive: 'Provide full technical analysis and data verification.',
        haniel_directive: 'Provide full catalyst and data freshness analysis.',
        raziel_directive: 'Provide full counter-thesis with at least 5 failure modes.',
        sariel_directive: 'Search for the latest news and real-time data.',
        priorityagents: [],
        depriorityagents: [],
        portfoliocontext: null,
        routingrationale: 'PASS1 PARSE FAILED — using generic routing'
      };
    }
  }

  const enriched = {
    ...originalInput,
    pass1routing: routing,
    priorityagents: routing.priorityagents || routing.priority_agents || [],
    depriorityagents: routing.depriorityagents || routing.depriority_agents || [],
    portfoliocontext: routing.portfoliocontext || routing.portfolio_context || null
  };

  results.push({ json: enriched });
}

return results;

// GITHUB STATUS — surfaces push result instead of swallowing errors
const input = $input.first().json;

// Check if we got a response from GitHub
const statusCode = input?.statusCode || input?.headers?.status || null;
const body = input?.body || input;

let result = {
  github_push_success: false,
  github_push_status: 'unknown',
  github_push_url: null,
  github_push_error: null,
  // Pass through everything from OUTPUT FORMATTER
  ...$input.first().json
};

// GitHub returns 201 for created, 200 for updated
if (statusCode === 201 || statusCode === 200) {
  result.github_push_success = true;
  result.github_push_status = statusCode === 201 ? 'CREATED' : 'UPDATED';
  result.github_push_url = body?.content?.html_url || 'url not in response';
} else if (body?.content?.html_url) {
  // fullResponse might not be enabled — check if we got content directly
  result.github_push_success = true;
  result.github_push_status = 'CREATED';
  result.github_push_url = body.content.html_url;
} else if (body?.html_url) {
  result.github_push_success = true;
  result.github_push_status = 'CREATED';
  result.github_push_url = body.html_url;
} else {
  // Failure
  result.github_push_success = false;
  result.github_push_status = `FAILED (${statusCode || 'no status'})`;
  result.github_push_error = JSON.stringify(body).substring(0, 500);
}

return [{ json: result }];

// CIL v5.2 DIAGNOSTIC ENGINE — Validates data correctness, not just execution
// [FIX v5.2.1] Agent lookup: agentresults array has no .agent field — use index mapping
// [FIX v5.2.1] Added diagnostictelegram field for ERROR TELEGRAM node

const input = $input.first().json;
const issues = [];
const runId = input.runid || 'NO-RUN-ID';

// Agent name-to-index mapping (matches OUTPUT FORMATTER array order)
const agents = ['URIEL', 'COLOSSUS', 'HANIEL', 'RAZIEL', 'SARIEL'];
const agentResults = input.agentresults || [];

// [FIX v5.2.1] Use index-based lookup since agentresults is a positional array
// agentresults[0] = URIEL, [1] = COLOSSUS, [2] = HANIEL, [3] = RAZIEL, [4] = SARIEL
for (let i = 0; i < agents.length; i++) {
  const agent = agents[i];
  const result = agentResults[i]; // positional — no .agent field exists

  if (!result) {
    issues.push({ severity: 'ERROR', node: agent, detail: 'Agent returned no data' });
  } else if (result.error) {
    issues.push({ severity: 'ERROR', node: agent, detail: `Agent error: ${result.error}` });
  } else {
    if (!result.direction || !['BULLISH', 'BEARISH', 'NEUTRAL'].includes(result.direction.toUpperCase())) {
      issues.push({ severity: 'WARN', node: agent, detail: `Invalid direction: ${result.direction}` });
    }
    if (result.confidence !== undefined && (result.confidence < 0 || result.confidence > 100)) {
      issues.push({ severity: 'WARN', node: agent, detail: `Confidence out of range: ${result.confidence}` });
    }
    if (!result.risks || result.risks.length === 0) {
      issues.push({ severity: 'WARN', node: agent, detail: 'No risks identified (possible analysis gap)' });
    }
    if (result.data_gaps && result.data_gaps.length > 0) {
      issues.push({ severity: 'INFO', node: agent, detail: `Data gaps reported: ${result.data_gaps.length} items` });
    }
  }
}

// Check cascade integrity
if (!input.cascadelevel) {
  issues.push({ severity: 'ERROR', node: 'CASCADE VALIDATOR', detail: 'No cascade level produced' });
}

// Check for PASS2 synthesis failure
if (!input.pass2synthesis || Object.keys(input.pass2synthesis).length === 0) {
  issues.push({ severity: 'ERROR', node: 'MICHA PASS2', detail: 'Synthesis returned empty — possible API failure' });
}

// Check for flags
if (input.flags && input.flags.length > 0) {
  for (const flag of input.flags) {
    issues.push({ severity: 'FLAG', node: 'CASCADE', detail: flag });
  }
}

const errorIssues = issues.filter(i => i.severity === 'ERROR');
const warnIssues = issues.filter(i => i.severity === 'WARN');
const hasErrors = errorIssues.length > 0;
const hasWarnings = warnIssues.length > 0;

// [FIX v5.2.1] Build diagnostictelegram string for ERROR TELEGRAM node
let diagnosticLines = [];
diagnosticLines.push(`🔧 CIL DIAGNOSTIC REPORT`);
diagnosticLines.push(`━━━━━━━━━━━━━━━━`);
diagnosticLines.push(`RUN: ${runId}`);
diagnosticLines.push(`ERRORS: ${errorIssues.length} | WARNINGS: ${warnIssues.length}`);
diagnosticLines.push(``);

for (const issue of issues) {
  const icon = issue.severity === 'ERROR' ? '🔴' : issue.severity === 'WARN' ? '🟡' : issue.severity === 'FLAG' ? '🚩' : 'ℹ️';
  diagnosticLines.push(`${icon} [${issue.node}] ${issue.detail}`);
}

diagnosticLines.push(``);
diagnosticLines.push(`━━━━━━━━━━━━━━━━`);

return {
  json: {
    runid: runId,
    hasissues: hasErrors,
    haswarnings: hasWarnings,
    issuecount: issues.length,
    errorcount: errorIssues.length,
    issues: issues,
    diagnostictelegram: diagnosticLines.join('\n'),
    diagnostictimestamp: new Date().toISOString()
  }
};

// CIL v5.2 EMAIL BACKUP — [EDIT — URIEL] Secondary delivery channel
// Only fires for FULL_CONFIDENCE and HIGH_CONFIDENCE signals
// [FIX v5.2] No-underscore convention
const input = $input.first().json;
const level = input.cascadelevel || 'LOW';

if (level !== 'FULL_CONFIDENCE' && level !== 'HIGH_CONFIDENCE') {
  return [];
}

const emailBody = {
  to: 'ashes2echoes.platform@gmail.com',
  subject: `🔱 AIORA ${level}: ${input.ticker} — ${input.runid}`,
  body: `CASCADE: ${level} (${input.gatespassed}/${input.gatestotal} gates)
TICKER: ${input.ticker}
DIRECTION: ${input.consensusdirection}
CONFIDENCE (annotative): ${input.avgconfidenceannotative}%
DATA COMPLETENESS: ${input.datacompleteness}
FLAGS: ${(input.flags || []).join(', ') || 'None'}
RUN-ID: ${input.runid}
TIMESTAMP: ${input.timestamp}`,
  runid: input.runid
};

return { json: emailBody };

// PASS2 RESULT CHECK — Detects Claude API failures and routes accordingly
const input = $input.first().json;

// Check for error indicators
const hasError = !!input.error;
const httpError = input.statusCode && input.statusCode >= 400;
const emptyResponse = !input.content && !input.choices;
const isFailure = hasError || httpError || emptyResponse;

return [{
  json: {
    ...input,
    pass2_failed: isFailure,  // BOOLEAN, not string
    failure_reason: isFailure
      ? (input.error?.message || input.error || 'Unknown PASS2 failure')
      : null
  }
}];

// CIL v5.0 TEST VALIDATOR — Validates output structure and data quality
const input = $input.first().json;
const runId = input.runid || 'NO-RUN-ID';
const ticker = input.ticker || 'UNKNOWN';

// Test suite
const tests = [];

// Test 1: Run ID present
tests.push({
  test: 'runidpresent',
  pass: !!input.runid,
  detail: input.runid || 'Missing'
});

// Test 2: Cascade level valid
const validLevels = ['FULL_CONFIDENCE', 'HIGH_CONFIDENCE', 'MODERATE', 'LOW'];
tests.push({
  test: 'cascadelevelvalid',
  pass: validLevels.includes(input.cascadelevel),
  detail: input.cascadelevel || 'Missing'
});

// Test 3: Gates scored
tests.push({
  test: 'gates_scored',
  pass: input.gatespassed !== undefined && input.gatestotal !== undefined,
  detail: `${input.gatespassed || 0}/${input.gatestotal || 0}`
});

// Test 4: Agent results present
const agentCount = (input.agentresults || []).length;
tests.push({
  test: 'agent_resultspresent',
  pass: agentCount >= 3,
  detail: `${agentCount}/5 agents returned data`
});

// Test 5: Consensus direction valid
const validDirections = ['BULLISH', 'BEARISH', 'NO_CONSENSUS'];
tests.push({
  test: 'consensusdirectionvalid',
  pass: validDirections.includes(input.consensusdirection),
  detail: input.consensusdirection || 'Missing'
});

// Test 6: Pass2 synthesis present
tests.push({
  test: 'pass2synthesispresent',
  pass: input.pass2synthesis && Object.keys(input.pass2synthesis).length > 0,
  detail: input.pass2synthesis ? 'Present' : 'Missing'
});

// Test 7: Telegram message formatted
tests.push({
  test: 'telegrammessageformatted',
pass: !!input.telegrammessage && input.telegrammessage.includes(ticker),
  detail: input.telegrammessage ? 'Formatted' : 'Missing'
});

// Test 8: GitHub path generated
tests.push({
  test: 'githubpathgenerated',
  pass: !!input.githubpath && input.githubpath.includes(runId),
  detail: input.githubpath || 'Missing'
});

// Test 9: Data completeness calculated
tests.push({
  test: 'datacompletenesscalculated',
  pass: !!input.datacompleteness,
  detail: input.datacompleteness || 'Missing'
});

// Test 10: Flags array present
tests.push({
  test: 'flagsarraypresent',
  pass: Array.isArray(input.flags),
  detail: `${(input.flags || []).length} flags`
});

// Calculate pass rate
const passCount = tests.filter(t => t.pass).length;
const totalTests = tests.length;
const passRate = (passCount / totalTests * 100).toFixed(1);

return {
  json: {
    runid: runId,
    ticker: ticker,
    testtimestamp: new Date().toISOString(),
    testspassed: passCount,
    teststotal: totalTests,
    passrate: passRate + '%',
    teststatus: passCount === totalTests ? 'PASS' : passCount >= totalTests * 0.8 ? 'WARN' : 'FAIL',
    testdetails: tests,
    fulloutput: input
  }
};

