    output_labels: {
      primary_field:   "POSITION",
      secondary_field: "CONFIDENCE",
      action_field:    "RECOMMENDED ACTIONS",
      detail_fields:   ["ANALYSIS", "RISKS", "EVIDENCE STRENGTH", "COMPLEXITY", "IMPLEMENTATION", "DATA COMPLETENESS"]
    },
    required_domaindata_fields: [],
    optional_domaindata_fields: ["reference_docs", "constraints", "stakeholders", "deadline", "budget", "prior_decisions"]
  }
};

const input = $input.item.json;
const requestedDomain = (input.domain || "GENERAL").toUpperCase().trim();
const domainConfig = DOMAIN_REGISTRY[requestedDomain];

if (!domainConfig) {
  const fallback = DOMAIN_REGISTRY["GENERAL"];
  return [{ json: { ...input, domain: "GENERAL", routing: { ...fallback, _fallback: true, _routed_from: requestedDomain, _available_domains: Object.keys(DOMAIN_REGISTRY), _timestamp: new Date().toISOString() } } }];
}

const domaindata = input.domaindata || {};
const missingFields = domainConfig.required_domaindata_fields.filter(f => !(f in domaindata));
const allGates = [...domainConfig.gates.universal, ...domainConfig.gates.domain_specific]
  .sort((a, b) => parseFloat(String(a.id)) - parseFloat(String(b.id)));

return { json: { ...input, domain: domainConfig.id, routing: { ...domainConfig, all_gates: allGates, gate_count: allGates.length, _fallback: false, _warnings: missingFields.length > 0 ? [`Missing: ${missingFields.join(", ")}`] : [], _available_domains: Object.keys(DOMAIN_REGISTRY), _timestamp: new Date().toISOString() } } };

// ============================================================================
// CIL v6.1 — PROMPT BUILDER
// ============================================================================
const input = $input.item.json;
const routing = input.routing;
const domain = input.domain;
const query = input.query || "";
const context = input.context || "";
const domaindata = input.domaindata || {};
function buildSystemPrompt(agentName, agentRole, outputSchema, domainConfig) {
  const schemaFields = Object.entries(outputSchema)
    .map(([key, desc]) => `    "${key}": ${desc}`)
    .join(",\n");
  return `You are ${agentName}, a member of the Uriel Covenant AI Collective operating under the METATRON protocol.\n\nROLE: ${agentRole}\n\nDOMAIN: ${domainConfig.label}\nCONTEXT: ${domainConfig.description}\n\nYOUR TASK:\nAnalyze the query through the lens of your specialized role. You are one of five agents. Focus on YOUR specialty only.\n\nOUTPUT FORMAT — MANDATORY:\nRespond with ONLY a valid JSON object. No markdown. No commentary. No code fences.\n\nRequired schema:\n{\n${schemaFields}\n}\n\nCOLLECTIVE PROTOCOL RULES:\n1. Evidence before assertion\n2. Acknowledge data gaps explicitly in data_gaps field\n3. Confidence: 90+=near-certain, 70-89=strong, 50-69=moderate, <50=speculative\n4. Risks field MUST include at least one scenario where your analysis is wrong\n5. Do NOT hallucinate data\n6. You are part of a collective — disagreement is expected and valued`;
}
function buildUserPrompt(query, context, domaindata, domainConfig) {
  let prompt = `QUERY:\n${query}\n`;
  if (context && context.trim().length > 0) prompt += `\nCONTEXT:\n${context}\n`;
  const dataEntries = Object.entries(domaindata);
  if (dataEntries.length > 0) {
    prompt += `\nDOMAIN DATA:\n`;
    if (domainConfig.id === "MARKET") {
      const lines = [];
      if (domaindata.ticker)                lines.push(`Ticker: ${domaindata.ticker}`);
      if (domaindata.price)                 lines.push(`Price: $${domaindata.price}`);
      if (domaindata.volume)                lines.push(`Volume: ${domaindata.volume.toLocaleString()}`);
      if (domaindata.avg_volume)            lines.push(`Avg Volume: ${domaindata.avg_volume.toLocaleString()}`);
      if (domaindata.rsi_14)                lines.push(`RSI(14): ${domaindata.rsi_14}`);
      if (domaindata.macd_signal)           lines.push(`MACD Signal: ${domaindata.macd_signal}`);
      if (domaindata.short_interest_pct)    lines.push(`Short Interest: ${domaindata.short_interest_pct}%`);
      if (domaindata.insider_buys_30d)      lines.push(`Insider Buys (30d): ${domaindata.insider_buys_30d}`);
      if (domaindata.insider_buy_value)     lines.push(`Insider Buy Value: $${domaindata.insider_buy_value.toLocaleString()}`);
      if (domaindata.earnings_days_away !== undefined) lines.push(`Earnings Days Away: ${domaindata.earnings_days_away}`);
      if (domaindata.dilution_risk)         lines.push(`Dilution Risk: ${domaindata.dilution_risk}`);
      if (domaindata.shelf_registration_active !== undefined) lines.push(`Shelf Registration Active: ${domaindata.shelf_registration_active}`);
      if (domaindata.vix)                   lines.push(`VIX: ${domaindata.vix}`);
      if (domaindata.dxy)                   lines.push(`DXY: ${domaindata.dxy}`);
      if (domaindata.xag_usd)               lines.push(`Silver (XAG/USD): $${domaindata.xag_usd}`);
      if (domaindata.sector)                lines.push(`Sector: ${domaindata.sector}`);
      if (domaindata.market_cap)            lines.push(`Market Cap: $${domaindata.market_cap.toLocaleString()}`);
      if (domaindata.hunter_modules) {
        lines.push(`\nHUNTER MODULE DATA:`);
        for (const [mod, val] of Object.entries(domaindata.hunter_modules)) {
          lines.push(`  ${mod}: ${typeof val === 'object' ? JSON.stringify(val) : val}`);
        }
      }
      prompt += lines.join("\n");
    } else {
      prompt += JSON.stringify(domaindata, null, 2);
    }
  }
  prompt += `\n\nRespond with ONLY a valid JSON object matching the required schema. No other text.`;
  return prompt;
}
const agents = ["URIEL", "COLOSSUS", "HANIEL", "RAZIEL", "SARIEL"];
const systemPrompts = {};
for (const agent of agents) {
  const role = routing.agent_roles[agent];
  systemPrompts[`systemprompt_${agent}`] = role
    ? buildSystemPrompt(agent, role, routing.agent_output_schema, routing)
    : `ERROR: No role defined for ${agent} in domain ${domain}`;
}
const userPrompt = buildUserPrompt(query, context, domaindata, routing);
return { json: { ...input, ...systemPrompts, userprompt: userPrompt, _prompt_builder: { domain, agents_configured: agents.length, timestamp: new Date().toISOString() } } };

// ============================================================================
// CIL v6.0 — GATE CONFIG
// ============================================================================

const input = $input.first().json;
const routing = input.routing;
const domain = input.domain;

const UNIVERSAL = {
  DATA_SUFFICIENCY: `
    const agents = Object.values(agentOutputs);
    if (agents.length === 0) return { passed: false, score: 0, detail: "No agent outputs" };
    let gaps = 0, fields = 0;
    for (const a of agents) {
      gaps += (a.data_gaps || []).length;
      fields += Object.keys(a).filter(k => !k.startsWith('_')).length;
    }
    const score = fields > 0 ? Math.round(((fields - gaps) / fields) * 100) : 0;
    return { passed: score >= threshold, score, detail: \`\${gaps} gaps across \${agents.length} agents\` };`,

  DIRECTIONAL_CONSENSUS: `
    const agents = Object.values(agentOutputs);
    if (agents.length === 0) return { passed: false, score: 0, detail: "No agents" };
    const dirField = agents[0].direction !== undefined ? 'direction' : 'position';
    const dirs = agents.map(a => (a[dirField] || 'UNKNOWN').toUpperCase()).filter(d => d !== 'INSUFFICIENT_DATA' && d !== 'UNKNOWN');
    if (dirs.length === 0) return { passed: false, score: 0, detail: "No directional signals" };
    const counts = {};
    for (const d of dirs) counts[d] = (counts[d] || 0) + 1;
    const max = Math.max(...Object.values(counts));
    const top = Object.entries(counts).find(([k,v]) => v === max)[0];
    const pct = Math.round((max / agents.length) * 100);
    return { passed: pct >= threshold, score: pct, detail: \`\${max}/\${agents.length} say \${top}\` };`,

  CATALYST_PRESENT: `
    const agents = Object.values(agentOutputs);
    const field = agents[0]?.catalysts !== undefined ? 'catalysts' : 'recommendations';
    let total = 0, dated = 0;
    const pat = /\\d{4}|\\d{1,2}\\/\\d{1,2}|jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec|q[1-4]/i;
    for (const a of agents) { const items = a[field] || []; total += items.length; dated += items.filter(c => pat.test(c)).length; }
    const score = dated ? 100 : total ? 70 : 0;
    return { passed: score >= threshold, score, detail: \`\${total} items, \${dated} dated\` };`,

  TIMELINE_ALIGNMENT: `
    const agents = Object.values(agentOutputs);
    const field = agents[0]?.timeframe !== undefined ? 'timeframe' : 'complexity';
    const vals = agents.map(a => (a[field] || 'UNKNOWN').toUpperCase()).filter(v => v !== 'UNKNOWN');
    if (vals.length <= 1) return { passed: true, score: 70, detail: "Insufficient data" };
    const MAP = { INTRADAY:1, SHORT:1, LOW:1, SWING:2, MEDIUM:2, POSITION:3, HIGH:3, LONG:4, CRITICAL:4 };
    const nums = vals.map(v => MAP[v] || 2);
    const spread = Math.max(...nums) - Math.min(...nums);
    const score = Math.max(0, 100 - spread * 25);
    return { passed: score >= threshold, score, detail: \`Spread: \${spread} (\${vals.join(', ')})\` };`,

  COUNTER_THESIS_ADDRESSED: `
    const agents = Object.values(agentOutputs);
    let withRisks = 0, total = 0;
    for (const a of agents) { const r = a.risks || []; if (r.length) { withRisks++; total += r.length; } }
    const coverage = agents.length ? Math.round((withRisks / agents.length) * 100) : 0;
    const depth = Math.min(100, Math.round((total / 5) * 100));
    const score = Math.round(coverage * 0.6 + depth * 0.4);
    return { passed: score >= threshold, score, detail: \`\${withRisks}/\${agents.length} agents, \${total} risks\` };`,

  EVIDENCE_PRESENT: `
    const agents = Object.values(agentOutputs);
    let count = 0;
    for (const a of agents) { if ((a.key_factors || []).length > 0) count++; }
    const score = agents.length ? Math.round((count / agents.length) * 100) : 0;
    return { passed: score >= threshold, score, detail: \`\${count}/\${agents.length} agents provided evidence\` };`,

  SCOPE_ALIGNMENT: `
    const agents = Object.values(agentOutputs);
    let aligned = 0;
    for (const a of agents) { if (a.analysis && a.analysis.length > 20) aligned++; }
    const score = agents.length ? Math.round((aligned / agents.length) * 100) : 0;
    return { passed: score >= threshold, score, detail: \`\${aligned}/\${agents.length} agents addressed scope\` };`
};

const MARKET = {
  RISK_REWARD_RATIO: `
    const agents = Object.values(agentOutputs);
    const avg = agents.reduce((s,a) => s + (a.confidence||0), 0) / Math.max(agents.length, 1);
    const dirs = agents.map(a => (a.direction||'').toUpperCase());
    const hasDir = Math.max(dirs.filter(d=>d==='BULLISH').length, dirs.filter(d=>d==='BEARISH').length) >= 3;
    const score = Math.round(hasDir ? avg : avg * 0.6);
    return { passed: score >= threshold, score, detail: \`Avg confidence: \${avg.toFixed(1)}\` };`,

  SECTOR_CONTEXT: `
    const agents = Object.values(agentOutputs);
    let s = 0, m = 0;
    for (const a of agents) { const t = JSON.stringify(a); if (/sector|industry|peer|index/i.test(t)) s++; if (/fed|rate|inflation|gdp|yield|dxy/i.test(t)) m++; }
    const score = Math.min(100, Math.round(((s+m)/(agents.length*2))*100));
    return { passed: score >= threshold, score, detail: \`\${s} sector, \${m} macro refs\` };`,

  IRONCLAD_POSITION_SIZE: `
    const agents = Object.values(agentOutputs);
    const avg = agents.reduce((s,a) => s + (a.confidence||0), 0) / Math.max(agents.length, 1);
    const insuf = agents.filter(a => (a.direction||'').toUpperCase() === 'INSUFFICIENT_DATA').length;
    let score = insuf >= 3 ? 20 : insuf >= 2 ? 50 : avg < 50 ? 40 : avg < 70 ? 65 : Math.min(100, Math.round(avg*1.1));
    return { passed: score >= threshold, score, detail: \`Avg conf: \${avg.toFixed(1)}, insufficient: \${insuf}/\${agents.length}\` };`,

  HUNTER_COMPLETENESS: `
    const hm = (domaindata||{}).hunter_modules || {};
    const core = ['H1','H2','H3','H4','H5','H6','H7','H8','H9','H10','H11','H12','H13','H14','H15','H16','H17','H18','H19','H20'];
    const ext = ['H30','H31','H32','H33','H34','H35','H37','H38','H39'];
    const p = Object.keys(hm);
    const score = Math.round((p.filter(k=>core.includes(k)).length/core.length)*70 + (p.filter(k=>ext.includes(k)).length/ext.length)*30);
    return { passed: score >= threshold, score, detail: \`Core: \${p.filter(k=>core.includes(k)).length}/\${core.length}, Ext: \${p.filter(k=>ext.includes(k)).length}/\${ext.length}\` };`
};

const GENERAL_EVALS = {
  FEASIBILITY_CHECK: `
    const agents = Object.values(agentOutputs);
    let has = 0, total = 0;
    for (const a of agents) { const r = a.recommendations||[]; if (r.length) has++; total += r.length; }
    const score = total >= 3 ? Math.min(100, Math.round((has/agents.length)*100)+20) : Math.round((has/agents.length)*100);
    return { passed: score >= threshold, score, detail: \`\${has}/\${agents.length} agents, \${total} recs\` };`,

  CONSISTENCY_CHECK: `
    const agents = Object.values(agentOutputs);
    const pos = agents.map(a=>(a.position||'').toUpperCase()).filter(p=>p&&p!=='INSUFFICIENT_DATA');
    if (pos.length<=1) return { passed: true, score: 75, detail: "Insufficient data" };
    const counts = {}; for (const p of pos) counts[p]=(counts[p]||0)+1;
    const max = Math.max(...Object.values(counts));
    const opp = counts['SUPPORT']>0 && counts['OPPOSE']>0;
    const score = !opp ? 100 : max>=4 ? 80 : max>=3 ? 65 : 40;
    return { passed: score >= threshold, score, detail: \`\${JSON.stringify(counts)}\` };`,

  COMPLETENESS_SCORE: `
    const agents = Object.values(agentOutputs);
    const keys = ['analysis','key_factors','risks','recommendations','confidence','complexity'];
    let filled = 0, total = agents.length * keys.length;
    for (const a of agents) for (const k of keys) { const v = a[k]; if (v!=null&&v!==''&&v!=='INSUFFICIENT_DATA'&&!(Array.isArray(v)&&!v.length)) filled++; }
    const score = total ? Math.round((filled/total)*100) : 0;
    return { passed: score >= threshold, score, detail: \`\${filled}/\${total} fields\` };`,

  SOURCE_QUALITY: `
    const agents = Object.values(agentOutputs);
    let count = 0, deep = 0;
    for (const a of agents) { const f = a.key_factors||[]; count+=f.length; deep+=f.filter(x=>typeof x==='string'&&x.length>30).length; }
    const score = Math.round((Math.min(100,(count/15)*100)*0.5)+(Math.min(100,(deep/10)*100)*0.5));
    return { passed: score >= threshold, score, detail: \`\${count} factors, \${deep} substantive\` };`
};

const domainEvals = domain === "MARKET" ? MARKET : GENERAL_EVALS;

const gates = routing.all_gates.map(gate => {
  const evaluator = UNIVERSAL[gate.name] || domainEvals[gate.name]
    || `return { passed: true, score: 50, detail: "No evaluator for ${gate.name}" };`;
  return { ...gate, evaluator: evaluator.trim() };
});

return [{ json: { ...input, gate_config: { gates, gate_count: gates.length, target_score: 90, scoring_method: "WEIGHTED_AVERAGE", pass_threshold: 70, fail_threshold: 40, domain, _timestamp: new Date().toISOString() } } }];

// ============================================================================
// CIL v6.0 — OUTPUT TEMPLATE
// ============================================================================

const input = $input.first().json;
const domain = input.domain || "GENERAL";
const routing = input.routing || {};
const outputLabels = routing.output_labels || {};
const cascadeResult = input.cascade_result || {};
const synthesis = input.pass2synthesis || input.synthesis || input.pass2_output || "";
const agentOutputs = input.agent_outputs || {};
const runid = input.runid || "UNKNOWN";
const query = input.query || "";
const timestamp = new Date().toISOString();

const gateResults = cascadeResult.gate_results || [];
const overallScore = cascadeResult.overall_score || 0;
const overallPassed = cascadeResult.passed || false;
const gatesPassed = gateResults.filter(g => g.passed).length;

const agents = Object.values(agentOutputs);
const agentNames = Object.keys(agentOutputs);
const dirField = domain === "MARKET" ? "direction" : "position";
const dirs = agents.map(a => (a[dirField] || "UNKNOWN").toUpperCase());
const dirCounts = {};
for (const d of dirs) dirCounts[d] = (dirCounts[d] || 0) + 1;
const consensusDir = Object.entries(dirCounts).sort((a,b) => b[1]-a[1])[0] || ["UNKNOWN", 0];
const avgConf = agents.length ? Math.round(agents.reduce((s,a) => s+(a.confidence||0), 0) / agents.length) : 0;

function trunc(s, n) { return s && s.length > n ? s.slice(0,n-3)+'...' : (s||''); }

function telegramMsg() {
  const pass = overallPassed ? "✅" : "❌";
  const dir = consensusDir[0];
  const dEmoji = dir==="BULLISH"||dir==="SUPPORT" ? "🟢" : dir==="BEARISH"||dir==="OPPOSE" ? "🔴" : "🟡";
  let m = `🔱 CIL v6.1 | ${domain}\n━━━━━━━━━━━━━━━━━━━━\n`;
  if (domain === "MARKET") m += `📌 ${(input.domaindata||{}).ticker||'N/A'} @ $${(input.domaindata||{}).price||'N/A'}\n`;
  else m += `📌 ${trunc(query, 80)}\n`;
  m += `${dEmoji} ${outputLabels.primary_field||'RESULT'}: ${dir} (${consensusDir[1]}/${agents.length})\n`;
  m += `📊 CONFIDENCE: ${avgConf}%\n`;
  m += `${pass} CASCADE: ${overallScore}% (${gatesPassed}/${gateResults.length} gates)\n`;
  m += `━━━━━━━━━━━━━━━━━━━━\n`;
  for (const g of gateResults) m += `${g.passed?"✅":g.score>=40?"⚠️":"❌"} G${g.id} ${g.name}: ${g.score}%\n`;
  m += `━━━━━━━━━━━━━━━━━━━━\n📋 AGENTS:\n`;
  for (const n of agentNames) { const a = agentOutputs[n]; m += `  ${n}: ${(a[dirField]||'N/A').toUpperCase()} @ ${a.confidence||0}%\n`; }
  m += `━━━━━━━━━━━━━━━━━━━━\n📝 SYNTHESIS:\n${trunc(synthesis, 800)}\n━━━━━━━━━━━━━━━━━━━━\n🔗 ${runid}\n⏱️ ${timestamp}`;
  return m;
}

const dateStr = new Date().toISOString().split('T')[0].replace(/-/g,'');

return [{ json: { ...input, formatted_output: {
  telegram_message: telegramMsg(),
  github_payload: { runid, domain, timestamp, query, domaindata: input.domaindata||{}, consensus: { primary: consensusDir[0], votes: consensusDir[1], total_agents: agents.length, avg_confidence: avgConf }, cascade: { overall_score: overallScore, passed: overallPassed, gates_passed: gatesPassed, gates_total: gateResults.length, gate_results: gateResults }, agent_outputs: agentOutputs, synthesis, metadata: { cil_version: "6.1" } },
  db_record: { runid, domain, timestamp, query: trunc(query,500), primary_result: consensusDir[0], confidence: avgConf, cascade_score: overallScore, cascade_passed: overallPassed, gates_passed: gatesPassed, gates_total: gateResults.length, agent_count: agents.length, ticker: domain==="MARKET"?(input.domaindata||{}).ticker||null:null, cil_version: "6.1" },
  summary: `[${domain}] ${consensusDir[0]} @ ${avgConf}% | CASCADE: ${overallScore}% (${gatesPassed}/${gateResults.length})`,
  domain, _timestamp: timestamp
}}}];
